//! Wrapper script generation for optional build acceleration

use std::fs;
use std::path::Path;

pub(in crate::actions::build::accel) fn format_build_accel_config() -> String {
    // A wrapper script keeps builds working if accelerator tools disappear later
    let lines: Vec<String> = vec![
        "# Optional build acceleration for UnixNotis".to_string(),
        "# Generated by unixnotis-installer; delete to disable".to_string(),
        "# Wrapper falls back to rustc if accelerators are unavailable".to_string(),
        String::new(),
        "[build]".to_string(),
        "rustc-wrapper = \".cargo/unixnotis-rustc-wrapper.sh\"".to_string(),
        String::new(),
    ];

    lines.join("\n")
}

pub(in crate::actions::build::accel) fn write_wrapper_script(
    wrapper_path: &Path,
) -> Result<(), String> {
    if let Some(parent) = wrapper_path.parent() {
        // Create the wrapper parent first so the later config write has a valid target
        fs::create_dir_all(parent).map_err(|err| err.to_string())?;
    }
    fs::write(wrapper_path, wrapper_script()).map_err(|err| err.to_string())?;
    set_wrapper_permissions(wrapper_path).map_err(|err| err.to_string())?;
    Ok(())
}

pub(in crate::actions::build::accel) fn wrapper_script() -> String {
    // Keep the script inline here so config generation and runtime behavior stay in one module
    [
        "#!/usr/bin/env sh",
        "# UnixNotis build accelerator wrapper",
        "# Routes builds through sccache or mold when available",
        "# Falls back to rustc when accelerator tools are missing",
        "# Clippy is forwarded directly to avoid argument conflicts",
        "",
        "set -e",
        "",
        "COMPILER=\"$1\"",
        "shift",
        "",
        // Clippy passes both the driver and rustc through the wrapper, so unwrap that shape first
        "case \"$COMPILER\" in",
        "  *clippy-driver*)",
        "    RUSTC=\"$1\"",
        "    shift",
        "    exec \"$COMPILER\" \"$RUSTC\" \"$@\"",
        "    ;;",
        "esac",
        "",
        "RUSTC=\"$COMPILER\"",
        "",
        // Prefer sccache first so repeated local builds can reuse compiled artifacts
        "if command -v sccache >/dev/null 2>&1; then",
        "  if command -v mold >/dev/null 2>&1; then",
        "    exec sccache \"$RUSTC\" -C link-arg=-fuse-ld=mold \"$@\"",
        "  fi",
        "  exec sccache \"$RUSTC\" \"$@\"",
        "fi",
        "",
        // If only mold exists, keep the faster linker without adding a cache layer
        "if command -v mold >/dev/null 2>&1; then",
        "  exec \"$RUSTC\" -C link-arg=-fuse-ld=mold \"$@\"",
        "fi",
        "",
        "exec \"$RUSTC\" \"$@\"",
        "",
    ]
    .join("\n")
}

#[cfg(unix)]
fn set_wrapper_permissions(wrapper_path: &Path) -> std::io::Result<()> {
    use std::os::unix::fs::PermissionsExt;

    let mut perms = fs::metadata(wrapper_path)?.permissions();
    // The wrapper must be executable or Cargo cannot launch it
    perms.set_mode(0o755);
    fs::set_permissions(wrapper_path, perms)
}

#[cfg(not(unix))]
fn set_wrapper_permissions(_wrapper_path: &Path) -> std::io::Result<()> {
    Ok(())
}
